// components/FechamentoMensal.js
// Tela de fechamento financeiro.
// O usuário escolhe mês e ano, e o sistema calcula tudo com base nos shows.

import { useState } from 'react';
import { getFechamento } from '../services/api';

const MESES = [
  { value: 1, label: 'Janeiro' },
  { value: 2, label: 'Fevereiro' },
  { value: 3, label: 'Março' },
  { value: 4, label: 'Abril' },
  { value: 5, label: 'Maio' },
  { value: 6, label: 'Junho' },
  { value: 7, label: 'Julho' },
  { value: 8, label: 'Agosto' },
  { value: 9, label: 'Setembro' },
  { value: 10, label: 'Outubro' },
  { value: 11, label: 'Novembro' },
  { value: 12, label: 'Dezembro' },
];

function moeda(valor) {
  return new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
  }).format(valor || 0);
}

export default function FechamentoMensal() {
  const hoje = new Date();
  const [mes, setMes] = useState(hoje.getMonth() + 1);
  const [ano, setAno] = useState(hoje.getFullYear());
  const [fechamento, setFechamento] = useState(null);
  const [loading, setLoading] = useState(false);
  const [erro, setErro] = useState('');

  async function buscar() {
    setErro('');
    setFechamento(null);
    setLoading(true);
    try {
      const data = await getFechamento(mes, ano);
      setFechamento(data);
    } catch (err) {
      setErro(err.message);
    } finally {
      setLoading(false);
    }
  }

  const nomeMes = MESES.find((m) => m.value === Number(mes))?.label;

  return (
    <div className="card">
      <h2 className="card-title">
        <span className="icon">💰</span> Fechamento Mensal
      </h2>

      <div className="filtro-row">
        <div className="form-group">
          <label>Mês</label>
          <select
            value={mes}
            onChange={(e) => setMes(e.target.value)}
            className="input"
          >
            {MESES.map((m) => (
              <option key={m.value} value={m.value}>
                {m.label}
              </option>
            ))}
          </select>
        </div>

        <div className="form-group">
          <label>Ano</label>
          <input
            type="number"
            value={ano}
            onChange={(e) => setAno(e.target.value)}
            className="input"
            min="2020"
            max="2099"
          />
        </div>

        <button className="btn btn-primary btn-buscar" onClick={buscar} disabled={loading}>
          {loading ? 'Calculando...' : 'Calcular'}
        </button>
      </div>

      {erro && <div className="alert alert-erro">{erro}</div>}

      {fechamento && (
        <div className="fechamento-resultado">
          <h3 className="fechamento-titulo">
            {nomeMes} / {ano} — {fechamento.quantidadeShows} show{fechamento.quantidadeShows !== 1 ? 's' : ''}
          </h3>

          <div className="cards-grid">
            <div className="resultado-card resultado-bruto">
              <div className="resultado-label">Total Bruto</div>
              <div className="resultado-valor">{moeda(fechamento.totalBruto)}</div>
            </div>

            <div className="resultado-card resultado-daniel">
              <div className="resultado-label">Daniel</div>
              <div className="resultado-valor">{moeda(fechamento.totalDaniel)}</div>
              <div className="resultado-detalhe">15% + R$40 transporte/dia</div>
            </div>

            <div className="resultado-card resultado-yuri">
              <div className="resultado-label">Yuri</div>
              <div className="resultado-valor">{moeda(fechamento.totalYuri)}</div>
              <div className="resultado-detalhe">R$300 fixo por show</div>
            </div>

            <div className={`resultado-card ${fechamento.lucroLiquido >= 0 ? 'resultado-lucro' : 'resultado-prejuizo'}`}>
              <div className="resultado-label">Lucro Líquido</div>
              <div className="resultado-valor">{moeda(fechamento.lucroLiquido)}</div>
            </div>
          </div>

          {fechamento.shows.length > 0 && (
            <div className="shows-fechamento">
              <h4>Shows do período</h4>
              {fechamento.shows.map((s) => (
                <div key={s.id} className="show-item">
                  <span className="show-data">
                    {s.data.split('-').reverse().join('/')}
                  </span>
                  <span className="show-local">{s.local}</span>
                  <span className="show-cache">
                    {s.valorCache ? moeda(s.valorCache) : 'R$ 110,00 (padrão)'}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
}
